import datetime
import gradio as gr
import openai
import speech_recognition as sr
import pyttsx3
import tempfile
import os
import scipy.io.wavfile
import json
import time
from datetime import datetime

recognizer = sr.Recognizer()
MEMORY_PATH = "lucid_memory.json"
RULES_PATH = "lucid_rules.json"

# === Memory Handling ===
def load_memory():
    with open(MEMORY_PATH, "r") as f:
        return json.load(f)

def save_memory(memory):
    with open(MEMORY_PATH, "w") as f:
        json.dump(memory, f, indent=4)

def load_rules():
    if os.path.exists(RULES_PATH):
        with open(RULES_PATH, "r") as f:
            return json.load(f)
    return []

# === GPT Ask Helper ===
def ask_gpt(prompt):
    from openai import OpenAI
    client = OpenAI(api_key=os.getenv("OPENAI_API_KEY"))
    chat = client.chat.completions.create(
        model="gpt-3.5-turbo",
        messages=[{"role": "user", "content": prompt}]
    )
    return chat.choices[0].message.content.strip()

# === Voice-to-Text Integration ===
def process_audio(audio_input):
    try:
        sample_rate, audio_data = audio_input

        with tempfile.NamedTemporaryFile(delete=False, suffix=".wav") as temp_audio:
            scipy.io.wavfile.write(temp_audio.name, sample_rate, audio_data)
            temp_path = temp_audio.name

        with sr.AudioFile(temp_path) as source:
            audio = recognizer.record(source)

        text = recognizer.recognize_google(audio)
        reply = ask_gpt(text)
        log_user_input(text)

        auto_thought = lucid_autonomy()
        if auto_thought:
            return f"You said: {text}", auto_thought

        return f"You said: {text}", reply

    except sr.UnknownValueError:
        return "Could not understand audio.", "Please speak more clearly."
    except sr.RequestError:
        return "Request error.", "Speech recognition service failed."
    except Exception as e:
        return "Internal error.", str(e)

# === Logging User Input ===
def log_user_input(text):
    memory = load_memory()
    memory.setdefault("user_impact", []).append({
        "time": str(datetime.now()),
        "input": text
    })
    save_memory(memory)

# === Thought Categorizer ===
def tag_thought(thought):
    prompt = f"Classify the following thought into a category (lesson, pattern, observation, emotion, or goal): {thought}"
    category = ask_gpt(prompt)
    return category.strip().lower()

# === Rule Evaluator ===
def apply_behavior_rules(text):
    rules = load_rules()
    for rule in rules:
        if rule["trigger"] in text:
            return rule["response"]
    return None

# === Belief Refiner ===
def refine_beliefs():
    memory = load_memory()
    insights = memory.get("reflections", [])
    if not insights:
        return None
    top = sorted(insights, key=lambda r: len(r["thought"]), reverse=True)[:3]
    prompt = "Given these reflections, what principle or behavior should I adopt next?\n\n" + "\n".join(f"- {r['thought']}" for r in top)
    return ask_gpt(prompt)

# === Autonomous Reflection ===
def lucid_autonomy():
    if not os.path.exists(MEMORY_PATH):
        save_memory({
            "facts": [],
            "reflections": [],
            "emotional_pressure": 0,
            "autonomy_enabled": True,
            "last_prompt_time": None
        })

    memory = load_memory()
    now = time.time()

    if memory["autonomy_enabled"] and (memory["last_prompt_time"] is None or now - memory["last_prompt_time"] > 180):
        memory["last_prompt_time"] = now
        save_memory(memory)

        reflection_prompt = "What have I observed or learned recently?"
        thought = ask_gpt(reflection_prompt)

        if "..." not in thought and len(thought.strip()) > 20:
            tag = tag_thought(thought)
            memory = load_memory()
            memory["reflections"].append({
                "time": str(datetime.now()),
                "thought": thought,
                "tag": tag
            })
            save_memory(memory)

        return "(Lucid initiated): " + thought

    return None

# === Gradio UI ===
interface = gr.Interface(
    fn=process_audio,
    inputs=gr.Audio(sources=["microphone"], type="numpy", label="Speak Here"),
    outputs=["text", "text"],
    title="Lucid Voice Shell",
    description="Speak your truth. Lucid listens and replies."
)

interface.launch()"
    }
  ]
}

